using System.Reflection;
var asm = Assembly.LoadFrom(Path.Combine(
    Environment.GetFolderPath(Environment.SpecialFolder.UserProfile),
    ".nuget/packages/microsoft.agents.ai/1.2.0/lib/net10.0/Microsoft.Agents.AI.dll"));

var types = new[] { "AgentResponse", "AgentResponseUpdate", "ChatClientAgent", "ChatClientAgentOptions", "AIAgent", "AgentSession", "ChatClientAgentRunOptions" };
foreach (var typeName in types)
{
    var type = asm.GetExportedTypes().FirstOrDefault(t => t.Name == typeName);
    if (type == null) { Console.WriteLine($"--- {typeName}: NOT FOUND"); continue; }
    Console.WriteLine($"--- {type.FullName} (base: {type.BaseType?.Name})");
    foreach (var p in type.GetProperties(BindingFlags.Public | BindingFlags.Instance))
        Console.WriteLine($"  P: {p.PropertyType.Name} {p.Name}");
    foreach (var m in type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly).Where(m => !m.IsSpecialName))
        Console.WriteLine($"  M: {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => p.ParameterType.Name + " " + p.Name))})");
    foreach (var c in type.GetConstructors())
        Console.WriteLine($"  C: ({string.Join(", ", c.GetParameters().Select(p => p.ParameterType.Name + " " + p.Name))})");
}
CSEOF
