var agentsAi = Assembly.LoadFrom(Path.Combine(nugetBase, "microsoft.agents.ai/1.2.0/lib/net10.0/Microsoft.Agents.AI.dll"));

// Look in all loaded assemblies
foreach (var asm in AppDomain.CurrentDomain.GetAssemblies())
{
    foreach (var t in asm.GetTypes().Where(t => 
        t.Name == "AgentResponse" || t.Name == "AIAgent" || t.Name == "AgentSession" || t.Name == "AgentRunOptions"))
    {
        Console.WriteLine($"[{asm.GetName().Name}] {t.FullName} (public={t.IsPublic}, base={t.BaseType?.Name})");
        foreach (var p in t.GetProperties(BindingFlags.Public | BindingFlags.Instance))
            Console.WriteLine($"  P: {p.PropertyType.Name} {p.Name}");
        foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly).Where(m => !m.IsSpecialName).Take(10))
            Console.WriteLine($"  M: {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => p.ParameterType.Name))})");
    }
}
