using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var modelId = "gpt-4o-mini-2024-07-18";

Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔍 Research Agent              ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.Write("\nEnter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

// Build the IChatClient through MEAI abstractions
IChatClient chatClient = new OpenAI.OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// Define the tools the agent can use
var tools = new AITool[]
{
    AIFunctionFactory.Create(ResearchTools.SearchWeb),
    AIFunctionFactory.Create(ResearchTools.TakeNote),
    AIFunctionFactory.Create(ResearchTools.GetNotes),
};

// Create the agent with Microsoft Agent Framework
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Your goal is to thoroughly research the user's topic
        by searching the web, taking notes on key findings, and then providing a
        comprehensive summary.

        Follow this process:
        1. Break the topic into 2-3 specific search queries.
        2. For each query, use SearchWeb to find relevant information.
        3. Use TakeNote to record each important finding (include the source URL).
        4. After gathering enough information, use GetNotes to review all your notes.
        5. Provide a final, well-structured summary with key findings and sources.

        Be thorough but concise. Cite sources where possible.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics using web search and note-taking.",
    tools: tools);

var session = await agent.CreateSessionAsync();

var options = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
});

// Stream the agent's response
await foreach (var update in agent.RunStreamingAsync(
    $"Research this topic thoroughly: {topic}",
    session,
    options))
{
    if (update.Text is { Length: > 0 } text)
    {
        Console.Write(text);
    }
}

Console.WriteLine("\n\n--- Research complete ---");

// Display collected notes
if (ResearchTools.Notes.Count > 0)
{
    Console.WriteLine($"\n📝 {ResearchTools.Notes.Count} note(s) were recorded during research.");
}

/// <summary>
/// Tools available to the research agent for web searching and note-taking.
/// </summary>
static class ResearchTools
{
    private static readonly HttpClient HttpClient = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
    };

    public static List<string> Notes { get; } = [];

    [Description("Search the web for information on a query. Returns a list of search result snippets with titles and URLs.")]
    public static async Task<string> SearchWeb(
        [Description("The search query to look up")] string query)
    {
        Console.WriteLine($"  🔎 Searching: \"{query}\"");

        try
        {
            // Use DuckDuckGo Instant Answer API (no key required)
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_redirect=1&no_html=1";

            var response = await HttpClient.GetFromJsonAsync<JsonElement>(url);

            var results = new List<string>();

            // Extract the abstract if available
            var abstractText = response.GetProperty("Abstract").GetString();
            var abstractUrl = response.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.Add($"[Summary] {abstractText} (Source: {abstractUrl})");
            }

            // Extract related topics
            if (response.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var item in topics.EnumerateArray().Take(5))
                {
                    if (item.TryGetProperty("Text", out var text) &&
                        item.TryGetProperty("FirstURL", out var itemUrl))
                    {
                        var snippet = text.GetString();
                        var link = itemUrl.GetString();
                        if (!string.IsNullOrWhiteSpace(snippet))
                        {
                            results.Add($"- {snippet} (Source: {link})");
                        }
                    }
                }
            }

            if (results.Count == 0)
            {
                return $"No detailed results found for \"{query}\". Try a more specific or alternative query.";
            }

            return string.Join("\n", results);
        }
        catch (Exception ex)
        {
            return $"Search failed for \"{query}\": {ex.Message}. Try a different query.";
        }
    }

    [Description("Save a research note. Use this to record important findings during research.")]
    public static string TakeNote(
        [Description("The note content to save, including source attribution")] string note)
    {
        Notes.Add(note);
        Console.WriteLine($"  📝 Note #{Notes.Count} saved");
        return $"Note #{Notes.Count} saved successfully.";
    }

    [Description("Retrieve all saved research notes to review findings before writing a summary.")]
    public static string GetNotes()
    {
        if (Notes.Count == 0)
        {
            return "No notes have been taken yet.";
        }

        var result = $"=== {Notes.Count} Research Note(s) ===\n";
        for (int i = 0; i < Notes.Count; i++)
        {
            result += $"\n[Note {i + 1}]\n{Notes[i]}\n";
        }

        return result;
    }
}

