/// <summary>
/// Tools available to the research agent for web searching and note-taking.
/// </summary>
static class ResearchTools
{
    private static readonly HttpClient HttpClient = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
    };

    public static List<string> Notes { get; } = [];

    [Description("Search the web for information on a query. Returns a list of search result snippets with titles and URLs.")]
    public static async Task<string> SearchWeb(
        [Description("The search query to look up")] string query)
    {
        Console.WriteLine($"  🔎 Searching: \"{query}\"");

        try
        {
            // Use DuckDuckGo Instant Answer API (no key required)
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_redirect=1&no_html=1";

            var response = await HttpClient.GetFromJsonAsync<JsonElement>(url);

            var results = new List<string>();

            // Extract the abstract if available
            var abstractText = response.GetProperty("Abstract").GetString();
            var abstractUrl = response.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.Add($"[Summary] {abstractText} (Source: {abstractUrl})");
            }

            // Extract related topics
            if (response.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var item in topics.EnumerateArray().Take(5))
                {
                    if (item.TryGetProperty("Text", out var text) &&
                        item.TryGetProperty("FirstURL", out var itemUrl))
                    {
                        var snippet = text.GetString();
                        var link = itemUrl.GetString();
                        if (!string.IsNullOrWhiteSpace(snippet))
                        {
                            results.Add($"- {snippet} (Source: {link})");
                        }
                    }
                }
            }

            if (results.Count == 0)
            {
                return $"No detailed results found for \"{query}\". Try a more specific or alternative query.";
            }

            return string.Join("\n", results);
        }
        catch (Exception ex)
        {
            return $"Search failed for \"{query}\": {ex.Message}. Try a different query.";
        }
    }

    [Description("Save a research note. Use this to record important findings during research.")]
    public static string TakeNote(
        [Description("The note content to save, including source attribution")] string note)
    {
        Notes.Add(note);
        Console.WriteLine($"  📝 Note #{Notes.Count} saved");
        return $"Note #{Notes.Count} saved successfully.";
    }

    [Description("Retrieve all saved research notes to review findings before writing a summary.")]
    public static string GetNotes()
    {
        if (Notes.Count == 0)
        {
            return "No notes have been taken yet.";
        }

        var result = $"=== {Notes.Count} Research Note(s) ===\n";
        for (int i = 0; i < Notes.Count; i++)
        {
            result += $"\n[Note {i + 1}]\n{Notes[i]}\n";
        }

        return result;
    }
}

